class Node:
    def __init__(self, data):
        self.data = data
        self.next = None

class LinkedList:
    def __init__(self):
        self.head = None

    def append(self, data):
        new_node = Node(data)
        if not self.head:
            self.head = new_node
            return
        last = self.head
        while last.next:
            last = last.next
        last.next = new_node

    def delete_n_nodes_after_m_nodes(self, m, n):
        if not self.head or m < 1 or n < 0:
            return

        current = self.head
        count_m = 1

        while current and count_m < m:
            current = current.next
            count_m += 1

        if not current:
            return

        node_after_m_plus_n_nodes = current.next
        count_n = 0

        while node_after_m_plus_n_nodes and count_n < n:
            node_after_m_plus_n_nodes = node_after_m_plus_n_nodes.next
            count_n += 1

        current.next = node_after_m_plus_n_nodes

    def print_list(self):
        current = self.head
        while current:
            print(current.data, end=" -> ")
            current = current.next
        print("None")
